import java.util.*;

class Solution {
    public static int solve(String[] tokens) {
        Deque<Integer> stack = new ArrayDeque<>();
        for (String t : tokens) {
            if ("+-*/".contains(t)) {
                int b = stack.pop(), a = stack.pop();
                switch (t) {
                    case "+": stack.push(a+b); break;
                    case "-": stack.push(a-b); break;
                    case "*": stack.push(a*b); break;
                    case "/": stack.push((int)(a/b)); break;
                }
            } else stack.push(Integer.parseInt(t));
        }
        return stack.peek();
    }
}

