    public static boolean solve(int[] numbers) {
        if (numbers.length < 3) return false;
        int i = 0;
        while (i+1 < numbers.length && numbers[i] < numbers[i+1]) i++;
        if (i == 0 || i == numbers.length-1) return false;
        while (i+1 < numbers.length && numbers[i] > numbers[i+1]) i++;
        return i == numbers.length-1;
    }
}

