import java.util.*;

class Solution {
    public static int solve(int[] numbers) {
        Map<Integer,Integer> freq = new LinkedHashMap<>();
        for (int n : numbers) freq.merge(n, 1, Integer::sum);
        for (Map.Entry<Integer,Integer> e : freq.entrySet()) if (e.getValue() == 1) return e.getKey();
        return -1;
    }
}
